import{_ as a,c as i,o as t,aj as r}from"./chunks/framework.D11sAc3v.js";const g=JSON.parse('{"title":"Scraping Page URL","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/field-types/scraper-data/scraping-page-url.md","filePath":"documentation/field-types/scraper-data/scraping-page-url.md","lastUpdated":0}'),s={name:"documentation/field-types/scraper-data/scraping-page-url.md"};function n(l,e,o,c,p,d){return t(),i("div",null,[...e[0]||(e[0]=[r(`<h1 id="scraping-page-url" tabindex="-1">Scraping Page URL <a class="header-anchor" href="#scraping-page-url" aria-label="Permalink to “Scraping Page URL”">​</a></h1><p>Extract the current page URL and store it in your Excel file.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>The Scraping Page URL field type allows you to capture the current web page&#39;s URL. This is useful for tracking which pages were visited, logging navigation paths, or using the URL in subsequent automation steps.</p><h2 id="configuration-options" tabindex="-1">Configuration Options <a class="header-anchor" href="#configuration-options" aria-label="Permalink to “Configuration Options”">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>Field Default Value</strong></td><td>Optional default URL value</td><td>No</td></tr></tbody></table><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to “How It Works”">​</a></h2><p>The Scraping Page URL field type has smart logic for determining what URL to capture:</p><ol><li><strong>If field value is undefined or empty</strong>: Scrapes the current page URL</li><li><strong>If field value is defined</strong>: Uses the defined default value instead</li></ol><p>This allows you to either dynamically capture the current URL or use a predefined URL value.</p><hr><h2 id="url-components" tabindex="-1">URL Components <a class="header-anchor" href="#url-components" aria-label="Permalink to “URL Components”">​</a></h2><p>When scraping the page URL, you get the complete URL including:</p><ul><li><strong>Protocol</strong>: <code>https://</code> or <code>http://</code></li><li><strong>Domain</strong>: <code>example.com</code></li><li><strong>Path</strong>: <code>/products/item-123</code></li><li><strong>Query Parameters</strong>: <code>?id=456&amp;category=electronics</code></li><li><strong>Hash/Fragment</strong>: <code>#section-2</code></li></ul><p><strong>Example Full URL:</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>https://example.com/products/item-123?id=456&amp;category=electronics#section-2</span></span></code></pre></div><hr><h2 id="usage-examples" tabindex="-1">Usage Examples <a class="header-anchor" href="#usage-examples" aria-label="Permalink to “Usage Examples”">​</a></h2><h3 id="example-1-capture-current-page-url" tabindex="-1">Example 1: Capture Current Page URL <a class="header-anchor" href="#example-1-capture-current-page-url" aria-label="Permalink to “Example 1: Capture Current Page URL”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Field Type: Scraping Page URL</span></span>
<span class="line"><span>Field Name: pageURL</span></span>
<span class="line"><span>Default Value: (empty)</span></span></code></pre></div><p><strong>Current Page:</strong> <code>https://formfiller.ctechhindi.in/example/form.php</code></p><p><strong>Result:</strong> Stores <code>https://formfiller.ctechhindi.in/example/form.php</code> in Excel column <code>pageURL</code></p><hr><h3 id="example-2-use-predefined-url" tabindex="-1">Example 2: Use Predefined URL <a class="header-anchor" href="#example-2-use-predefined-url" aria-label="Permalink to “Example 2: Use Predefined URL”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Field Type: Scraping Page URL</span></span>
<span class="line"><span>Field Name: targetURL</span></span>
<span class="line"><span>Default Value: https://example.com/default-page</span></span></code></pre></div><p><strong>Result:</strong> Stores <code>https://example.com/default-page</code> in Excel column <code>targetURL</code> (ignores current page URL)</p><hr><h3 id="example-3-track-navigation-path" tabindex="-1">Example 3: Track Navigation Path <a class="header-anchor" href="#example-3-track-navigation-path" aria-label="Permalink to “Example 3: Track Navigation Path”">​</a></h3><p><strong>Workflow:</strong></p><ol><li><strong>Field 1</strong> - Scraping Page URL (Start Page)</li><li><strong>Field 2</strong> - Click Button to Navigate</li><li><strong>Field 3</strong> - Scraping Page URL (End Page)</li></ol><p><strong>Result:</strong> Track the before and after URLs to verify navigation worked correctly.</p><hr><h3 id="example-4-dynamic-url-with-variables" tabindex="-1">Example 4: Dynamic URL with Variables <a class="header-anchor" href="#example-4-dynamic-url-with-variables" aria-label="Permalink to “Example 4: Dynamic URL with Variables”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Field Type: Scraping Page URL</span></span>
<span class="line"><span>Field Name: currentURL</span></span>
<span class="line"><span>Default Value: {$baseURL$}/page</span></span></code></pre></div><p><strong>Excel Column <code>baseURL</code>:</strong> <code>https://example.com</code></p><p><strong>Result:</strong> Stores <code>https://example.com/page</code> in Excel column <code>currentURL</code></p><hr><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to “Use Cases”">​</a></h2><h3 id="navigation-tracking" tabindex="-1">Navigation Tracking <a class="header-anchor" href="#navigation-tracking" aria-label="Permalink to “Navigation Tracking”">​</a></h3><p>Record which pages were visited during form filling for audit trails or debugging.</p><h3 id="url-verification" tabindex="-1">URL Verification <a class="header-anchor" href="#url-verification" aria-label="Permalink to “URL Verification”">​</a></h3><p>Verify that navigation to the correct page occurred before proceeding with form filling.</p><h3 id="dynamic-url-capture" tabindex="-1">Dynamic URL Capture <a class="header-anchor" href="#dynamic-url-capture" aria-label="Permalink to “Dynamic URL Capture”">​</a></h3><p>Capture URLs with dynamic parameters (like session IDs or tracking codes) for later reference.</p><h3 id="multi-page-forms" tabindex="-1">Multi-Page Forms <a class="header-anchor" href="#multi-page-forms" aria-label="Permalink to “Multi-Page Forms”">​</a></h3><p>Track progress through multi-page forms by recording the URL at each step.</p><h3 id="error-logging" tabindex="-1">Error Logging <a class="header-anchor" href="#error-logging" aria-label="Permalink to “Error Logging”">​</a></h3><p>Store the URL where an error occurred to help with troubleshooting and debugging.</p><h3 id="success-confirmation" tabindex="-1">Success Confirmation <a class="header-anchor" href="#success-confirmation" aria-label="Permalink to “Success Confirmation”">​</a></h3><p>Capture the final URL after form submission to confirm successful completion.</p><hr><h2 id="storing-url-data" tabindex="-1">Storing URL Data <a class="header-anchor" href="#storing-url-data" aria-label="Permalink to “Storing URL Data”">​</a></h2><p>The scraped URL is automatically stored in your Excel file in the column that matches the field name.</p><p><strong>Example:</strong></p><ul><li><strong>Field Name:</strong> <code>submissionURL</code></li><li><strong>Excel Column:</strong> <code>submissionURL</code></li><li><strong>Stored Value:</strong> <code>https://example.com/success?id=12345</code></li></ul><hr><h2 id="using-scraped-urls" tabindex="-1">Using Scraped URLs <a class="header-anchor" href="#using-scraped-urls" aria-label="Permalink to “Using Scraped URLs”">​</a></h2><p>You can reference the scraped URL in subsequent fields using variables:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>{$pageURL$}</span></span></code></pre></div><p><strong>Example Use Cases:</strong></p><ul><li>Compare URLs to verify navigation</li><li>Extract URL parameters using string manipulation</li><li>Log URLs for reporting purposes</li><li>Use URLs in API requests or custom JavaScript</li></ul><hr><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to “Tips”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Automatic vs Manual URL</p><p>Leave the default value empty to automatically capture the current page URL. Only set a default value if you want to override the automatic behavior.</p></div><div class="info custom-block"><p class="custom-block-title">URL Components</p><p>If you need specific parts of the URL (like just the hostname or pathname), consider using <a href="/documentation/variable.html">variables</a> like <code>{$location.hostname$}</code> or <code>{$location.pathname$}</code> instead.</p></div><div class="warning custom-block"><p class="custom-block-title">Dynamic URLs</p><p>Be aware that some websites use dynamic URLs with session tokens or timestamps. These URLs may change on each visit.</p></div><hr><h2 id="related-field-types" tabindex="-1">Related Field Types <a class="header-anchor" href="#related-field-types" aria-label="Permalink to “Related Field Types”">​</a></h2><ul><li><a href="/documentation/field-types/scraper-data/scraping-data.html">Scraping Data</a> - Extract data from page elements</li><li><a href="/documentation/field-types/url-matching.html">URL Matching</a> - Match and validate URL patterns</li><li><a href="/documentation/field-types/url-open.html">URL Open</a> - Navigate to specific URLs</li></ul><hr><h2 id="related-variables" tabindex="-1">Related Variables <a class="header-anchor" href="#related-variables" aria-label="Permalink to “Related Variables”">​</a></h2><ul><li><code>{$location.href$}</code> - Current page URL</li><li><code>{$location.hostname$}</code> - Domain name only</li><li><code>{$location.pathname$}</code> - Path portion only</li><li><code>{$location.search$}</code> - Query parameters only</li></ul><p>See <a href="/documentation/variable.html">Variables Documentation</a> for more details.</p>`,74)])])}const u=a(s,[["render",n]]);export{g as __pageData,u as default};
